#!/usr/bin/env bash
# seed_data.sh — Insert demo content into Supabase via REST API
# Usage: bash scripts/seed_data.sh

set -e

SERVICE_KEY="eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImF1c2luenh3Ym5pYnd0amFrbW1qIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3NTIxMjIzMiwiZXhwIjoyMDkwNzg4MjMyfQ.C3-3rhkzSPeN9s9bdH1omVgxe4nuh91ZzNk_a9w-w4Y"
BASE="https://ausinzxwbnibwtjakmmj.supabase.co/rest/v1"
H_API="-H apikey: $SERVICE_KEY"
H_AUTH="-H Authorization: Bearer $SERVICE_KEY"
H_CT="-H Content-Type: application/json"
H_PREF="-H Prefer: resolution=ignore-duplicates,return=minimal"

post() {
  local table="$1"
  local data="$2"
  local resp
  resp=$(curl -s -w "\n%{http_code}" -X POST "$BASE/$table" \
    -H "apikey: $SERVICE_KEY" \
    -H "Authorization: Bearer $SERVICE_KEY" \
    -H "Content-Type: application/json" \
    -H "Prefer: resolution=ignore-duplicates,return=minimal" \
    -d "$data")
  local code=$(echo "$resp" | tail -1)
  if [[ "$code" != "20"* ]]; then
    echo "  ⚠️  $table: HTTP $code — $(echo "$resp" | head -1)"
  fi
}

